1	import { createHmac, timingSafeEqual } from 'node:crypto';
2	
3	import { InjectQueue } from '@nestjs/bullmq';
4	import { Injectable, Logger } from '@nestjs/common';
5	import { Queue } from 'bullmq';
6	
7	import { EnvConfigService } from '@modules/env-config/env-config.service';
8	import { GithubInstallationModel } from '@modules/github/db/github-installations.model';
9	import { IGithubInstallationEvent } from '@modules/github/types/github-api.interface';
10	import { GithubInstallationStatus } from '@modules/github/types/github-installation.interface';
11	
12	import { GITHUB_APP_WEBHOOK_SECRET } from '@constants/env-variables.constant';
13	
14	@Injectable()
15	export class GithubWebhookService {
16		private readonly logger = new Logger(GithubWebhookService.name);
17	
18		constructor(
19			private readonly configService: EnvConfigService,
20			private readonly githubInstallationModel: GithubInstallationModel,
21			@InjectQueue('github') private readonly githubQueue: Queue,
22		) {}
23	
24		verifySignature({
25			payload,
26			signature,
27		}: {
28			payload: string;
29			signature: string;
30		}): boolean {
31			const secret = this.configService.get<string>({ key: GITHUB_APP_WEBHOOK_SECRET });
32			const computed = `sha256=${createHmac('sha256', secret).update(payload).digest('hex')}`;
33	
34			const trusted = Buffer.from(signature);
35			const untrusted = Buffer.from(computed);
36	
37			if (trusted.length !== untrusted.length) return false;
38			return timingSafeEqual(trusted, untrusted);
39		}
40	
41		async handleEvent({
42			event,
43			installationId,
44			payload,
45		}: {
46			event: string;
47			installationId: number;
48			payload: unknown;
49		}): Promise<void> {
50			const installation = await this.githubInstallationModel.findByInstallationId({
51				installationId,
52			});
53	
54			if (!installation) {
55				this.logger.warn(`Webhook received for unknown installation: ${installationId}`);
56				return;
57			}
58	
59			if (installation.status === GithubInstallationStatus.UNINSTALLED) {
60				this.logger.warn(
61					`Webhook received for uninstalled installation: ${installationId}`,
62				);
63				return;
64			}
65	
66			if (event === 'installation') {
67				await this.handleInstallationLifecycle({
68					installationId,
69					payload: payload as IGithubInstallationEvent,
70				});
71				return;
72			}
73	
74			if (installation.status === GithubInstallationStatus.SUSPENDED) {
75				this.logger.warn(`Dropping event for suspended installation: ${installationId}`);
76				return;
77			}
78	
79			await this.githubQueue.add('raw_event', {
80				event,
81				installationId,
82				payload,
83				receivedAt: new Date(),
84			});
85	
86			this.logger.debug(`Queued ${event} event for installation ${installationId}`);
87		}
88	
89		private async handleInstallationLifecycle({
90			installationId,
91			payload,
92		}: {
93			installationId: number;
94			payload: IGithubInstallationEvent;
95		}): Promise<void> {
96			if (payload.action === 'deleted') {
97				await this.githubInstallationModel.markUninstalled({ installationId });
98				this.logger.debug(`Installation ${installationId} uninstalled`);
99			} else if (payload.action === 'suspend') {
100				await this.githubInstallationModel.markSuspended({ installationId });
101				this.logger.debug(`Installation ${installationId} suspended`);
102			} else if (payload.action === 'unsuspend') {
103				await this.githubInstallationModel.markActive({ installationId });
104				this.logger.debug(`Installation ${installationId} unsuspended`);
105			}
106		}
107	}
