19		private readonly tableName = TABLE_NAME_GITHUB_INSTALLATIONS;
20	
21		constructor(
22			@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
23			@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
24		) {}
25	
26		async create({
27			data,
28		}: {
29			data: IGithubInstallationCreate;
30		}): Promise<IGithubInstallationBase> {
31			try {
32				const _id = randomUUID();
33				const [created] = await this.knexWrite<IGithubInstallationBase>(this.tableName)
34					.insert({
35						_id,
36						...data,
37						status: GithubInstallationStatus.ACTIVE,
38						installed_at: this.knexWrite.fn.now(),
39						created_at: this.knexWrite.fn.now(),
40						updated_at: this.knexWrite.fn.now(),
41					})
42					.returning('*');
43	
44				if (!created) {
45					throw new Error('Failed to create github installation');
46				}
47	
48				this.logger.debug(`Created github installation ${_id}`);
49				return created;
50			} catch (error) {
51				this.logger.error(
52					`Failed to create github installation: ${(error as Error).message}`,
53				);
54				throw error;
55			}
56		}
