58		async findByInstallationId({
59			installationId,
60		}: {
61			installationId: number;
62		}): Promise<IGithubInstallationBase | null> {
63			try {
64				const result = await this.knexRead<IGithubInstallationBase>(this.tableName)
65					.where({ installation_id: installationId })
66					.first();
67	
68				return result ?? null;
69			} catch (error) {
70				this.logger.error(
71					`Failed to find installation by installation_id ${installationId}: ${(error as Error).message}`,
72				);
73				throw error;
74			}
75		}
76	
77		async markUninstalled({ installationId }: { installationId: number }): Promise<void> {
78			try {
79				await this.knexWrite<IGithubInstallationBase>(this.tableName)
80					.where({ installation_id: installationId })
81					.update({
82						status: GithubInstallationStatus.UNINSTALLED,
83						uninstalled_at: this.knexWrite.fn.now(),
84						updated_at: this.knexWrite.fn.now(),
85					});
86	
87				this.logger.debug(`Marked installation ${installationId} as uninstalled`);
88			} catch (error) {
89				this.logger.error(
90					`Failed to mark installation ${installationId} as uninstalled: ${(error as Error).message}`,
91				);
92				throw error;
93			}
94		}
95	
96		async markSuspended({ installationId }: { installationId: number }): Promise<void> {
97			try {
98				await this.knexWrite<IGithubInstallationBase>(this.tableName)
99					.where({ installation_id: installationId })
100					.update({
101						status: GithubInstallationStatus.SUSPENDED,
102						suspended_at: this.knexWrite.fn.now(),
103						updated_at: this.knexWrite.fn.now(),
