69			installationId,
70		}: {
71			installationId: string;
72		}): Promise<IGithubRepoBase[]> {
73			try {
74				return await this.knexRead<IGithubRepoBase>(this.tableName)
75					.where({ installation_id: installationId })
76					.select('*');
77			} catch (error) {
78				this.logger.error(
79					`Failed to find repos for installation ${installationId}: ${(error as Error).message}`,
80				);
81				throw error;
82			}
83		}
84	
85		async findByGithubRepoId({
86			githubRepoId,
87		}: {
88			githubRepoId: number;
89		}): Promise<IGithubRepoBase | null> {
90			try {
91				const result = await this.knexRead<IGithubRepoBase>(this.tableName)
92					.where({ github_repo_id: githubRepoId })
93					.first();
94				return result ?? null;
95			} catch (error) {
96				this.logger.error(
97					`Failed to find repo by github_repo_id ${githubRepoId}: ${(error as Error).message}`,
98				);
99				throw error;
100			}
101		}
102	
103		async removeByGithubIds({
104			installationId,
105			githubRepoIds,
106		}: {
107			installationId: string;
108			githubRepoIds: number[];
109		}): Promise<void> {
110			if (githubRepoIds.length === 0) return;
111	
112			try {
113				await this.knexWrite<IGithubRepoBase>(this.tableName)
114					.where({ installation_id: installationId })
115					.whereIn('github_repo_id', githubRepoIds)
116					.delete();
117	
