import { Logger } from '@nestjs/common';
import { Processor, WorkerHost } from '@nestjs/bullmq';
import { Job } from 'bullmq';

import { GithubCommitModel } from '@modules/github/db/github-commit.model';
import { GithubContributorModel } from '@modules/github/db/github-contributor.model';
import { GithubInstallationModel } from '@modules/github/db/github-installations.model';
import { GithubPullRequestModel } from '@modules/github/db/github-pull-request.model';
import { GithubRepoModel } from '@modules/github/db/github-repos.model';
import { GithubReviewCommentModel } from '@modules/github/db/github-review-comment.model';
import { GithubReviewModel } from '@modules/github/db/github-review.model';
import {
	IGithubInstallationRepositoriesEvent,
	IGithubWebhookPREvent,
	IGithubWebhookPushEvent,
	IGithubWebhookReviewCommentEvent,
	IGithubWebhookReviewEvent,
} from '@modules/github/types/github-api.interface';
import { IGithubCommitUpsert } from '@modules/github/types/github-commit.interface';
import { GithubPRState } from '@modules/github/types/github-pull-request.interface';
import { GithubReviewState } from '@modules/github/types/github-review.interface';

interface IRawEventJob {
	event: string;
	installationId: number;
	payload: unknown;
	receivedAt: Date;
}

@Processor('github')
export class GithubEventProcessor extends WorkerHost {
	private readonly logger = new Logger(GithubEventProcessor.name);

	constructor(
		private readonly installationModel: GithubInstallationModel,
		private readonly repoModel: GithubRepoModel,
		private readonly contributorModel: GithubContributorModel,
		private readonly commitModel: GithubCommitModel,
		private readonly pullRequestModel: GithubPullRequestModel,
		private readonly reviewModel: GithubReviewModel,
		private readonly reviewCommentModel: GithubReviewCommentModel,
	) {
		super();
	}

	async process(job: Job<IRawEventJob>): Promise<void> {
		if (job.name !== 'raw_event') return;

		const { event, installationId, payload } = job.data;

		try {
			const installation = await this.installationModel.findByInstallationId({
				installationId,
			});

			if (!installation) {
				this.logger.warn(`No installation found for installationId: ${installationId}`);
				return;
			}

			switch (event) {
				case 'push':
					await this.handlePush({
						installationDbId: installation._id,
						payload: payload as IGithubWebhookPushEvent,
					});
					break;
				case 'pull_request':
					await this.handlePullRequest({
						installationDbId: installation._id,
						payload: payload as IGithubWebhookPREvent,
					});
					break;
				case 'pull_request_review':
					await this.handleReview({
						installationDbId: installation._id,
						payload: payload as IGithubWebhookReviewEvent,
					});
					break;
				case 'pull_request_review_comment':
					await this.handleReviewComment({
						installationDbId: installation._id,
						payload: payload as IGithubWebhookReviewCommentEvent,
					});
					break;
				case 'installation_repositories':
					await this.handleInstallationRepositories({
						installationDbId: installation._id,
						payload: payload as IGithubInstallationRepositoriesEvent,
					});
					break;
				default:
					this.logger.debug(`Unhandled event type: ${event}`);
			}
		} catch (error) {
			this.logger.error(
				`Failed to process ${event} event for installation ${installationId}: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	private async handlePush({
		installationDbId,
		payload,
	}: {
		installationDbId: string;
		payload: IGithubWebhookPushEvent;
	}): Promise<void> {
		const repo = await this.repoModel.findByGithubRepoId({
			githubRepoId: payload.repository.id,
		});

		if (!repo) {
			this.logger.warn(`Repo not found for github_repo_id: ${payload.repository.id}`);
			return;
		}

		const distinctCommits = payload.commits.filter((c) => c.distinct);

		if (distinctCommits.length === 0) return;

		for (const commit of distinctCommits) {
			if (commit.author.username) {
				await this.contributorModel.upsert({
					data: {
						installation_id: installationDbId,
						github_user_id: 0,
						github_login: commit.author.username,
						github_name: commit.author.name,
						github_email: commit.author.email,
					},
				});
			}
		}

		const commits: IGithubCommitUpsert[] = distinctCommits.map((c) => ({
			installation_id: installationDbId,
			repo_id: repo._id,
			sha: c.id,
			message: c.message,
			author_login: c.author.username ?? null,
			author_name: c.author.name,
			author_email: c.author.email,
			committed_at: new Date(c.timestamp),
			additions: 0,
			deletions: 0,
			is_merge_commit: (c.parents?.length ?? 0) > 1,
		}));

		await this.commitModel.upsertMany({ commits });
	}

	private async handlePullRequest({
		installationDbId,
		payload,
	}: {
		installationDbId: string;
		payload: IGithubWebhookPREvent;
	}): Promise<void> {
		const repo = await this.repoModel.findByGithubRepoId({
			githubRepoId: payload.repository.id,
		});

		if (!repo) {
			this.logger.warn(`Repo not found for github_repo_id: ${payload.repository.id}`);
			return;
		}

		const pr = payload.pull_request;

		await this.contributorModel.upsert({
			data: {
				installation_id: installationDbId,
				github_user_id: pr.user.id,
				github_login: pr.user.login,
			},
		});

		await this.pullRequestModel.upsert({
			data: {
				installation_id: installationDbId,
				repo_id: repo._id,
				github_pr_id: pr.id,
				pr_number: pr.number,
				title: pr.title,
				state: pr.state as GithubPRState,
				author_login: pr.user.login,
				draft: pr.draft,
				merged: pr.merged,
				additions: pr.additions,
				deletions: pr.deletions,
				changed_files: pr.changed_files,
				commits_count: pr.commits,
				opened_at: new Date(pr.created_at),
				merged_at: pr.merged_at ? new Date(pr.merged_at) : null,
				closed_at: pr.closed_at ? new Date(pr.closed_at) : null,
			},
		});
	}

	private async handleReview({
		installationDbId,
		payload,
	}: {
		installationDbId: string;
		payload: IGithubWebhookReviewEvent;
	}): Promise<void> {
		const repo = await this.repoModel.findByGithubRepoId({
			githubRepoId: payload.repository.id,
		});

		if (!repo) return;

		const pullRequest = await this.pullRequestModel.findByRepoAndNumber({
			repoId: repo._id,
			prNumber: payload.pull_request.number,
		});

		if (!pullRequest) {
			this.logger.warn(
				`Pull request #${payload.pull_request.number} not found for repo ${repo._id}`,
			);
			return;
		}

		const normalizedState = payload.review.state.toLowerCase();
		const validStates: string[] = [
			GithubReviewState.APPROVED,
			GithubReviewState.CHANGES_REQUESTED,
			GithubReviewState.COMMENTED,
			GithubReviewState.DISMISSED,
		];

		if (!validStates.includes(normalizedState)) return;

		await this.contributorModel.upsert({
			data: {
				installation_id: installationDbId,
				github_user_id: payload.review.user.id,
				github_login: payload.review.user.login,
			},
		});

		await this.reviewModel.upsert({
			data: {
				installation_id: installationDbId,
				pull_request_id: pullRequest._id,
				github_review_id: payload.review.id,
				reviewer_login: payload.review.user.login,
				state: normalizedState as GithubReviewState,
				submitted_at: new Date(payload.review.submitted_at),
			},
		});
	}

	private async handleReviewComment({
		installationDbId,
		payload,
	}: {
		installationDbId: string;
		payload: IGithubWebhookReviewCommentEvent;
	}): Promise<void> {
		if (payload.action === 'deleted') return;

		const repo = await this.repoModel.findByGithubRepoId({
			githubRepoId: payload.repository.id,
		});

		if (!repo) return;

		const pullRequest = await this.pullRequestModel.findByRepoAndNumber({
			repoId: repo._id,
			prNumber: payload.pull_request.number,
		});

		if (!pullRequest) {
			this.logger.warn(
				`Pull request #${payload.pull_request.number} not found for repo ${repo._id}`,
			);
			return;
		}

		await this.contributorModel.upsert({
			data: {
				installation_id: installationDbId,
				github_user_id: payload.comment.user.id,
				github_login: payload.comment.user.login,
			},
		});

		await this.reviewCommentModel.upsert({
			data: {
				installation_id: installationDbId,
				pull_request_id: pullRequest._id,
				github_comment_id: payload.comment.id,
				author_login: payload.comment.user.login,
				body: payload.comment.body,
				path: payload.comment.path,
				line: payload.comment.line,
				commented_at: new Date(payload.comment.created_at),
			},
		});
	}

	private async handleInstallationRepositories({
		installationDbId,
		payload,
	}: {
		installationDbId: string;
		payload: IGithubInstallationRepositoriesEvent;
	}): Promise<void> {
		if ((payload.repositories_added?.length ?? 0) > 0) {
			await this.repoModel.upsertMany({
				installationId: installationDbId,
				repos: payload.repositories_added,
			});
		}

		if ((payload.repositories_removed?.length ?? 0) > 0) {
			await this.repoModel.removeByGithubIds({
				installationId: installationDbId,
				githubRepoIds: payload.repositories_removed.map((r) => r.id),
			});
		}
	}
}

